class AgentMapAttnBias(nn.Module):
    """Attention bias for Agent-Map TSGFormer (Spatial, Directional, Edge Type, TTR)."""
    def __init__(self,
                 num_heads: int = 8,
                 num_spatial_bins: int = 100,
                 num_directional_bins: int = 36,
                 num_pl2a_edge_types: int = 8,
                 num_ttr_bins: int = 50,
                 hidden_dim: int = 128,
                 n_layers: int = 2,
                 max_distance: float = 50.0):
        super().__init__()
        self.num_heads = num_heads
        self.num_spatial_bins = num_spatial_bins
        self.num_directional_bins = num_directional_bins
        self.num_pl2a_edge_types = num_pl2a_edge_types
        self.num_ttr_bins = num_ttr_bins
        self.hidden_dim = hidden_dim
        self.max_distance = max_distance
        self.spatial_x_encoder = nn.Embedding(num_spatial_bins, num_heads)
        self.spatial_y_encoder = nn.Embedding(num_spatial_bins, num_heads)
        self.directional_encoder = nn.Embedding(num_directional_bins, num_heads)
        self.edge_type_encoder = nn.Embedding(num_pl2a_edge_types, num_heads)
        self.ttr_encoder = nn.Embedding(num_ttr_bins + 1, num_heads)
        self.gate_spatial = nn.Parameter(torch.tensor(0.0))
        self.gate_directional = nn.Parameter(torch.tensor(0.0))
        self.gate_edge = nn.Parameter(torch.tensor(0.5))
        self.gate_ttr = nn.Parameter(torch.tensor(0.5))
        self.bias_layernorm = nn.LayerNorm(num_heads)
        self.apply(lambda m: _init_params(m, n_layers=n_layers))

    def forward(self, rel_pos: torch.Tensor, relative_angle: torch.Tensor,
                edge_types: torch.Tensor, ttr_values: torch.Tensor) -> torch.Tensor:
        E = rel_pos.size(0)
        device = rel_pos.device
        if E == 0:
            return torch.zeros(0, self.num_heads, device=device)
        x_bins = torch.clamp(
            (rel_pos[:, 0].abs() / self.max_distance * self.num_spatial_bins).long(),
            0, self.num_spatial_bins - 1)
        y_bins = torch.clamp(
            (rel_pos[:, 1].abs() / self.max_distance * self.num_spatial_bins).long(),
            0, self.num_spatial_bins - 1)
        spatial_bias = self.spatial_x_encoder(x_bins) + self.spatial_y_encoder(y_bins)
        angle_normalized = (relative_angle + math.pi) / (2 * math.pi)
        angle_bins = torch.clamp(
            (angle_normalized * self.num_directional_bins).long(),
            0, self.num_directional_bins - 1)
        directional_bias = self.directional_encoder(angle_bins)
        edge_type_bias = self.edge_type_encoder(edge_types)
        ttr_bins = torch.clamp((ttr_values / 10.0 * self.num_ttr_bins).long(), 0, self.num_ttr_bins)
        ttr_bins = torch.where(
            torch.isinf(ttr_values) | (ttr_values > 100.0),
            torch.full_like(ttr_bins, self.num_ttr_bins),
            ttr_bins)
        ttr_bias = self.ttr_encoder(ttr_bins)
        g_s = torch.sigmoid(self.gate_spatial)
        g_d = torch.sigmoid(self.gate_directional)
        g_e = torch.sigmoid(self.gate_edge)
        g_t = torch.sigmoid(self.gate_ttr)
        combined_bias = (g_s * spatial_bias + g_d * directional_bias +
                         g_e * edge_type_bias + g_t * ttr_bias)
        return self.bias_layernorm(combined_bias)


class Pl2aTSGFormerLayer(nn.Module):
    """Polygon-to-Agent attention with TSGFormer-style biases (Agent=Query, Map=Key/Value)."""
    def __init__(self, hidden_dim: int, num_heads: int, head_dim: int, dropout: float,
                 num_freq_bands: int, num_spatial_bins: int = 100, num_directional_bins: int = 36,
                 num_pl2a_edge_types: int = 8, num_ttr_bins: int = 50, max_distance: float = 50.0):
        super().__init__()
        self.hidden_dim = hidden_dim
        self.num_heads = num_heads
        self.head_dim = head_dim
        self.scale = head_dim ** -0.5
        self.attn_bias = AgentMapAttnBias(
            num_heads=num_heads, num_spatial_bins=num_spatial_bins,
            num_directional_bins=num_directional_bins, num_pl2a_edge_types=num_pl2a_edge_types,
            num_ttr_bins=num_ttr_bins, hidden_dim=hidden_dim, max_distance=max_distance)
        self.centrality_encoder = nn.Linear(1, hidden_dim)
        self.q_proj = nn.Linear(hidden_dim, hidden_dim)
        self.k_proj = nn.Linear(hidden_dim, hidden_dim)
        self.v_proj = nn.Linear(hidden_dim, hidden_dim)
        self.layer_norm = nn.LayerNorm(hidden_dim)
        self.dropout = nn.Dropout(dropout)
        self.apply(lambda m: _init_params(m, n_layers=2))

    def forward(self, x_src: torch.Tensor, x_dst: torch.Tensor, edge_index: torch.Tensor,
                rel_pos: torch.Tensor, relative_angle: torch.Tensor, edge_types: torch.Tensor,
                ttr_values: torch.Tensor, centrality: torch.Tensor) -> torch.Tensor:
        E = edge_index.size(1)
        if E == 0:
            return x_dst
        centrality_emb = self.centrality_encoder(centrality.unsqueeze(-1))
        x_src_enhanced = x_src[edge_index[0]] + centrality_emb
        attn_bias = self.attn_bias(rel_pos, relative_angle, edge_types, ttr_values)
        q = self.q_proj(x_dst[edge_index[1]]).view(E, self.num_heads, self.head_dim)
        k = self.k_proj(x_src_enhanced).view(E, self.num_heads, self.head_dim)
        v = self.v_proj(x_src_enhanced).view(E, self.num_heads, self.head_dim)
        attn_scores = (q * k).sum(dim=-1) * self.scale + attn_bias
        dst_nodes = edge_index[1]
        num_dst = x_dst.size(0)
        attn_scores_max = torch.zeros(num_dst, self.num_heads, device=x_dst.device)
        attn_scores_max.scatter_reduce_(0, dst_nodes.unsqueeze(-1).expand(-1, self.num_heads),
                                        attn_scores, reduce='amax', include_self=True)
        attn_scores_exp = torch.exp(attn_scores - attn_scores_max[dst_nodes])
        attn_scores_sum = torch.zeros(num_dst, self.num_heads, device=x_dst.device)
        attn_scores_sum.scatter_add_(0, dst_nodes.unsqueeze(-1).expand(-1, self.num_heads), attn_scores_exp)
        attn_weights = self.dropout(attn_scores_exp / (attn_scores_sum[dst_nodes] + 1e-8))
        weighted_v = (attn_weights.unsqueeze(-1) * v).view(E, self.hidden_dim)
        out = torch.zeros(num_dst, self.hidden_dim, device=x_dst.device)
        out.scatter_add_(0, dst_nodes.unsqueeze(-1).expand(-1, self.hidden_dim), weighted_v)
        return self.layer_norm(x_dst + out)
